RAWRXD_STATUS __stdcall RawrXD_TokenizeInput(const char* prompt, int32_t* tokens, size_t max_tokens, uint32_t* token_count) {
    if (token_count == nullptr) {
        return Finish(RAWRXD_ERROR_INVALID_PARAM);
    }
    *token_count = 0;
    if (RequireInitialized() != RAWRXD_SUCCESS) {
        return g_last_error.load();
    }
    if (prompt == nullptr || tokens == nullptr || max_tokens == 0) {
        return Finish(RAWRXD_ERROR_INVALID_PARAM);
    }
    const size_t len = strlen(prompt);
    uint32_t count = 0;
    size_t i = 0;
    while (i < len && count < max_tokens) {
        while (i < len && (prompt[i] == ' ' || prompt[i] == '\n' || prompt[i] == '\t' || prompt[i] == '\r')) {
            ++i;
        }
        if (i >= len) {
            break;
        }
        size_t start = i;
        while (i < len && prompt[i] != ' ' && prompt[i] != '\n' && prompt[i] != '\t' && prompt[i] != '\r') {
            ++i;
        }
        tokens[count++] = static_cast<int32_t>((i - start) + 100);
    }
    *token_count = count;
    return Finish(RAWRXD_SUCCESS);
}

RAWRXD_STATUS __stdcall RawrXD_DetokenizeOutput(const int32_t* tokens, uint32_t token_count, char* output, size_t output_size) {
    if (output == nullptr || output_size == 0) {
        return Finish(RAWRXD_ERROR_INVALID_PARAM);
    }
    output[0] = 0;
    if (RequireInitialized() != RAWRXD_SUCCESS) {
        return g_last_error.load();
    }
    if (tokens == nullptr) {
        return Finish(RAWRXD_ERROR_INVALID_PARAM);
    }
    size_t used = 0;
    for (uint32_t i = 0; i < token_count; ++i) {
        char chunk[24];
        int written = _snprintf_s(chunk, sizeof(chunk), _TRUNCATE, "%d", tokens[i]);
        if (written <= 0) {
            break;
        }
        size_t need = static_cast<size_t>(written) + ((i + 1 < token_count) ? 1 : 0);
        if (used + need + 1 > output_size) {
            break;
        }
        memcpy(output + used, chunk, static_cast<size_t>(written));
        used += static_cast<size_t>(written);
        if (i + 1 < token_count) {
            output[used++] = ' ';
        }
    }
    output[used] = 0;
    return Finish(RAWRXD_SUCCESS);
}

