RAWRXD_STATUS __stdcall RawrXD_GetApertureUtilization(RAWRXD_APERTURE_STATUS* status) {
    if (status == nullptr) {
        return Finish(RAWRXD_ERROR_INVALID_PARAM);
    }
    ZeroIfPresent(status, sizeof(*status));
    if (RequireInitialized() != RAWRXD_SUCCESS) {
        return g_last_error.load();
    }
    std::lock_guard<std::mutex> lock(g_state_mutex);
    status->aperture_base = kApertureBase;
    status->aperture_total_bytes = kApertureTotalBytes;
    status->mapped_chunks = g_mapped_chunks;
    status->mapped_bytes = static_cast<uint64_t>(g_mapped_chunks) * 64ULL * 1024ULL * 1024ULL;
    status->unmapped_bytes = (status->mapped_bytes < kApertureTotalBytes) ?
        (kApertureTotalBytes - status->mapped_bytes) : 0;
    status->fragment_count = (g_mapped_chunks > 0) ? 1u : 0u;
    status->fragmentation_ratio = (g_mapped_chunks > 0) ? 0.05f : 0.0f;
    status->utilization_pct10000 = static_cast<uint32_t>((status->mapped_bytes * 1000000ULL) / kApertureTotalBytes);
    return Finish(RAWRXD_SUCCESS);
}

