RAWRXD_STATUS __stdcall RawrXD_AllocateBuffer(size_t size, void** buffer) {
    if (buffer == nullptr || size == 0) {
        return Finish(RAWRXD_ERROR_INVALID_PARAM);
    }
    *buffer = nullptr;
    if (RequireInitialized() != RAWRXD_SUCCESS) {
        return g_last_error.load();
    }
    void* mem = malloc(size);
    if (mem == nullptr) {
        return Finish(RAWRXD_ERROR_OUT_OF_MEMORY);
    }
    std::lock_guard<std::mutex> lock(g_state_mutex);
    g_allocations[mem] = size;
    g_mem_stats.total_allocated += size;
    g_mem_stats.currently_allocated += size;
    g_mem_stats.peak_allocated = std::max<uint64_t>(g_mem_stats.peak_allocated, g_mem_stats.currently_allocated);
    g_mem_stats.heap_blocks = static_cast<uint32_t>(g_allocations.size());
    g_mem_stats.heap_fragmentation = (g_mem_stats.heap_blocks > 1) ? 0.1f : 0.0f;
    g_mem_stats.virtual_address_space = g_mem_stats.currently_allocated;
    *buffer = mem;
    return Finish(RAWRXD_SUCCESS);
}

RAWRXD_STATUS __stdcall RawrXD_FreeBuffer(void* buffer) {
    if (buffer == nullptr) {
        return Finish(RAWRXD_ERROR_INVALID_PARAM);
    }
    if (RequireInitialized() != RAWRXD_SUCCESS) {
        return g_last_error.load();
    }
    std::lock_guard<std::mutex> lock(g_state_mutex);
    auto it = g_allocations.find(buffer);
    if (it == g_allocations.end()) {
        return Finish(RAWRXD_ERROR_INVALID_PARAM);
    }
    const size_t size = it->second;
    g_allocations.erase(it);
    free(buffer);
    g_mem_stats.currently_allocated = (g_mem_stats.currently_allocated >= size)
        ? (g_mem_stats.currently_allocated - size)
        : 0;
    g_mem_stats.heap_blocks = static_cast<uint32_t>(g_allocations.size());
    g_mem_stats.heap_fragmentation = (g_mem_stats.heap_blocks > 1) ? 0.1f : 0.0f;
    g_mem_stats.virtual_address_space = g_mem_stats.currently_allocated;
    return Finish(RAWRXD_SUCCESS);
}

