RAWRXD_STATUS __stdcall RawrXD_EnableHotpatch(void) {
    if (RequireInitialized() != RAWRXD_SUCCESS) {
        return g_last_error.load();
    }
    g_hotpatch_status |= 0x1u;
    return Finish(RAWRXD_SUCCESS);
}

RAWRXD_STATUS __stdcall RawrXD_ApplyHotpatch(const uint8_t* patch_data, size_t patch_size) {
    if (RequireInitialized() != RAWRXD_SUCCESS) {
        return g_last_error.load();
    }
    if ((g_hotpatch_status & 0x1u) == 0) {
        return Finish(RAWRXD_ERROR_HOTPATCH_FAILED);
    }
    if (patch_data == nullptr || patch_size == 0) {
        return FailInvalidParam();
    }
    g_stub_hotpatch_apply_calls.fetch_add(1, std::memory_order_relaxed);
    g_hotpatch_status |= 0x2u;
    return Finish(RAWRXD_SUCCESS);
}

RAWRXD_STATUS __stdcall RawrXD_QueryHotpatchStatus(uint32_t* status) {
    if (status == nullptr) {
        return Finish(RAWRXD_ERROR_INVALID_PARAM);
    }
    if (RequireInitialized() != RAWRXD_SUCCESS) {
        *status = 0;
        return g_last_error.load();
    }
    *status = g_hotpatch_status;
    return Finish(RAWRXD_SUCCESS);
}

RAWRXD_STATUS __stdcall RawrXD_EnableQuantization(uint32_t bits) {
    if (RequireInitialized() != RAWRXD_SUCCESS) {
        return g_last_error.load();
    }
    if (bits != 4 && bits != 8 && bits != 16 && bits != 32) {
        return Finish(RAWRXD_ERROR_INVALID_PARAM);
    }
    g_quantization_bits = bits;
    std::lock_guard<std::mutex> lock(g_state_mutex);
    if (g_model.loaded) {
        g_model.precision_bits = bits;
    }
    return Finish(RAWRXD_SUCCESS);
}

RAWRXD_STATUS __stdcall RawrXD_BatchInferences(const char** prompts, uint32_t prompt_count, RAWRXD_INFERENCE_HANDLE* batch_handle) {
    g_stub_batch_calls.fetch_add(1, std::memory_order_relaxed);
    if (batch_handle == nullptr || prompts == nullptr || prompt_count == 0) {
        return FailInvalidParam();
    }
    if (RequireInitialized() != RAWRXD_SUCCESS) {
        *batch_handle = 0;
        return g_last_error.load();
    }
    std::lock_guard<std::mutex> lock(g_state_mutex);
    if (!g_model.loaded) {
        *batch_handle = 0;
        return Finish(RAWRXD_ERROR_NO_MODEL_LOADED);
    }

    uint64_t total_in = 0;
    for (uint32_t i = 0; i < prompt_count; ++i) {
        if (prompts[i] == nullptr) {
            return FailInvalidParam();
        }
        total_in += EstimateTokenCount(prompts[i], strlen(prompts[i]));
    }

    const uint32_t in_tokens = static_cast<uint32_t>(std::min<uint64_t>(total_in, 0xFFFFFFFFULL));
    const uint32_t out_tokens = std::max<uint32_t>(1u, in_tokens / 2u);
    const double latency = static_cast<double>(prompt_count) * 3.0;
    UpdatePerfLocked(in_tokens, out_tokens, latency);

    g_last_inference.valid = true;
    g_last_inference.handle = g_next_inference_handle.fetch_add(1);
    g_last_inference.result = {};
    g_last_inference.result.input_token_count = in_tokens;
    g_last_inference.result.output_token_count = out_tokens;
    g_last_inference.result.latency_ms = static_cast<uint64_t>(latency);
    g_last_inference.result.status = RAWRXD_SUCCESS;

    *batch_handle = g_last_inference.handle;
    return Finish(RAWRXD_SUCCESS);
}

uint64_t __stdcall RawrXD_TitanStub_GetTelemetryPacked(void) {
    const uint64_t infer_async = static_cast<uint64_t>(g_stub_infer_async_calls.load(std::memory_order_relaxed) & 0xFFFFu);
    const uint64_t infer_sync = static_cast<uint64_t>(g_stub_infer_sync_calls.load(std::memory_order_relaxed) & 0xFFFFu);
    const uint64_t timeout_count = static_cast<uint64_t>(g_stub_timeout_count.load(std::memory_order_relaxed) & 0xFFFFu);
    const uint64_t invalid_count = static_cast<uint64_t>(g_stub_invalid_param_count.load(std::memory_order_relaxed) & 0xFFFFu);
    return infer_async | (infer_sync << 16) | (timeout_count << 32) | (invalid_count << 48);
}

uint64_t __stdcall RawrXD_TitanStub_GetTelemetryExtended(void) {
    const uint64_t batch_calls = static_cast<uint64_t>(g_stub_batch_calls.load(std::memory_order_relaxed) & 0xFFFFu);
    const uint64_t aperture_errors = static_cast<uint64_t>(g_stub_aperture_errors.load(std::memory_order_relaxed) & 0xFFFFu);
    const uint64_t hotpatch_calls = static_cast<uint64_t>(g_stub_hotpatch_apply_calls.load(std::memory_order_relaxed) & 0xFFFFu);
    const uint64_t diag_callback_calls = static_cast<uint64_t>(g_stub_diag_callback_calls.load(std::memory_order_relaxed) & 0xFFFFu);
    return batch_calls | (aperture_errors << 16) | (hotpatch_calls << 32) | (diag_callback_calls << 48);
}

void __stdcall RawrXD_TitanStub_ResetTelemetry(void) {
    ResetStubTelemetry();
}

